import math
    # Validate sides are positive
    if a <= 0 or b <= 0 or c <= 0:
        return -1
    # Check triangle inequality
    if a + b <= c or a + c <= b or b + c <= a:
        return -1
    # Heron's formula
    s = (a + b + c) / 2.0
    area_sq = s * (s - a) * (s - b) * (s - c)
    # Handle possible floating point inaccuracy
    if area_sq < 0:
        if area_sq > -1e-12:
            area_sq = 0.0
        else:
            return -1
    area = math.sqrt(area_sq)
    return float(f"{area:.2f}")
